// Recursive Drive scope: search PalmCo AND every subfolder (Drive's `in parents`
// is not recursive). List Folders (upstream) lists all owned folders; walk the
// parent->children map to collect ROOT + descendants and constrain to that set.
const ROOT = '1RCQF5970CpglBjehHS_jWSrD-hmenbjx'; // PalmCo knowledge base
const MAX_FOLDERS = 100;

const folders = $input.all().map(i => i.json).filter(f => f && f.id);
const childrenByParent = new Map();
for (const f of folders) {
  const parents = Array.isArray(f.parents) ? f.parents : (f.parentId ? [f.parentId] : []);
  for (const p of parents) {
    if (!childrenByParent.has(p)) childrenByParent.set(p, []);
    childrenByParent.get(p).push(f.id);
  }
}
const scope = new Set([ROOT]);
const stack = [ROOT];
while (stack.length) {
  const cur = stack.pop();
  for (const child of (childrenByParent.get(cur) || [])) {
    if (!scope.has(child)) { scope.add(child); stack.push(child); }
  }
}
const folderIds = [...scope].slice(0, MAX_FOLDERS);

const question = ($('Lookup Trigger').first().json || {}).question || '';

// Prefer LLM-extracted search terms (robust to phrasing, dates, synonyms). The
// "Extract Terms" chain (json_object mode) returns the parsed object directly as
// json.phrases / json.terms; a text-mode chain would return a JSON string in
// json.text. Handle both. Fall back to the local stopword + light-stemming
// heuristic only if that call failed or was empty.
let phrases = [];
let terms = [];
let source = 'llm';
try {
  const r = $('Extract Terms').first().json || {};
  let parsed = null;
  if (Array.isArray(r.phrases) || Array.isArray(r.terms)) {
    parsed = r;
  } else {
    const content = r.text != null ? r.text : (r.output != null ? r.output : (r.response != null ? r.response : ''));
    const s = String(content); const a = s.indexOf('{'); const b = s.lastIndexOf('}');
    if (a >= 0 && b > a) parsed = JSON.parse(s.slice(a, b + 1));
  }
  if (parsed) {
    if (Array.isArray(parsed.phrases)) phrases = parsed.phrases.map(x => String(x).trim()).filter(Boolean).slice(0, 3);
    if (Array.isArray(parsed.terms)) terms = parsed.terms.map(x => String(x).toLowerCase().trim()).filter(Boolean);
  }
} catch (e) {}
terms = [...new Set(terms)].slice(0, 12);

if (!terms.length) {
  source = 'heuristic';
  const STOP = new Set(['the','a','an','of','in','on','for','to','and','or','is','are','was','were','what','which','how','my','me','i','you','this','that','file','files','drive','google','about','please','summarize','explain','give','tell','show','find','list','from','with','it','its','based','document','documents','can','could','would','should','have','has','had','not','do','does','did','but','if','then','than','so','all','any','some','more','most','also','just','get','use','used','using','coba','cobalah','tolong','jelaskan','jelasin','jelaskanlah','berdasarkan','bedasarkan','carikan','cari','sebutkan','tuliskan','buatkan','berikan','apa','apakah','yang','dari','dan','atau','untuk','dengan','pada','adalah','saya','kamu','aku','ini','itu','dalam','tentang','mengenai','bisa','akan','juga','ada','nya','kah','dong','deh','nih','gimana','kasih','lihat','baca','isi','bagaimana','kenapa','mengapa','kapan','dimana','siapa','berapa','sudah','belum','sedang','telah','punya','mau','ingin','perlu']);
  const stripID = word => word.replace(/^(me|men|mem|meng|meny|ber|per|ke|se|di|ter|pe)/, '').replace(/(kan|an|nya|lah|kah|pun)$/, '');
  const phraseRegex = /"([^"]+)"/g;
  let m; let cq = question;
  while ((m = phraseRegex.exec(question)) !== null) { phrases.push(m[1].trim()); cq = cq.replace(m[0], ' '); }
  const rawWords = (cq.toLowerCase().match(/[a-z0-9]{2,}/g) || []);
  const kw = [];
  for (const w of rawWords) { if (!STOP.has(w)) kw.push(w); }
  for (const w of rawWords) { if (STOP.has(w)) continue; const st = stripID(w); if (st.length >= 4 && st !== w && !STOP.has(st)) kw.push(st); }
  terms = [...new Set(kw)].slice(0, 12);
  if (!terms.length) terms = (question.match(/[A-Za-z0-9]{2,}/g) || []).slice(0, 5);
}

const esc = s => String(s).replace(/'/g, "\\'");
const conditions = [];
for (const phrase of phrases) conditions.push(`fullText contains '${esc(phrase)}'`);
for (const term of terms) conditions.push(`fullText contains '${esc(term)}' or name contains '${esc(term)}'`);

const parentClause = folderIds.map(id => `'${esc(id)}' in parents`).join(' or ');
const scopeFilter = `trashed = false and 'me' in owners and (${parentClause})`;
const q = conditions.length ? `(${conditions.join(' or ')}) and ${scopeFilter}` : scopeFilter;

return [{ json: { q, question, terms, phrases, termCount: terms.length, scopeFolders: folderIds.length, source } }];

const terms = ($('Build Query').first().json.terms || []).map(t => String(t).toLowerCase());
const SIZE_CAP = 20 * 1024 * 1024, MAX = 1;
const items = $input.all();
const scored = [];
for (let idx = 0; idx < items.length; idx++) {
  const f = items[idx].json || {};
  if (!f.id) continue;
  if (f.size && Number(f.size) > SIZE_CAP) continue;
  const name = String(f.name || '').toLowerCase();
  let nameHits = 0;
  for (const t of terms) { if (t && name.indexOf(t) !== -1) nameHits++; }
  scored.push({ f: f, nameHits: nameHits, idx: idx });
}
scored.sort((a, b) => (b.nameHits - a.nameHits) || (a.idx - b.idx));
const out = [];
for (const s of scored) {
  out.push({ json: { driveFileId: s.f.id, filename: s.f.name, mimeType: s.f.mimeType, modifiedTime: s.f.modifiedTime } });
  if (out.length >= MAX) break;
}
return out;

const j = $input.first().json || {};
const text = j.text || '';
if (!text) return [];
return [{ json: { filename: j.filename || '', driveFileId: j.driveFileId || '', text: String(text) } }];

const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const bin = (items[i].binary && items[i].binary.file0) || {};
  const meta = $('Decide Cache').first().json;
  const fileName = bin.fileName || meta.filename || 'document';
  const ext = (bin.fileExtension || (fileName.split('.').pop() || '')).toLowerCase();
  out.push({ json: { filename: fileName, ext: ext, driveFileId: meta.driveFileId, modifiedTime: meta.modifiedTime, model: 'google/gemini-2.5-flash' }, binary: items[i].binary, pairedItem: { item: i } });
}
return out;

const file = $('Decide Cache').first().json;
const text = (($('Read Document').first().json) || {}).text || '';
return [{ json: { filename: file.filename, driveFileId: file.driveFileId, text: String(text) } }];

const fileItems = $('Pick Files').all();
if (!fileItems.length) return [];
const file = fileItems[0].json;
const cached = $input.first().json || {};
const hit = !!(cached.markdown && cached.modifiedTime === file.modifiedTime);
return [{ json: { hit: hit, driveFileId: file.driveFileId, filename: file.filename, modifiedTime: file.modifiedTime, markdown: hit ? cached.markdown : '' } }];
